    [
        .product(name: "SwiftQEMU", package: "swift-qemu"),
        .product(name: "SwiftOVN", package: "swift-ovn"),
    ]
}
#else
var qemuAndNetworkDependencies: [Target.Dependency] {
    // macOS: SwiftQEMU with HVF support, user-mode networking (no OVN/OVS)
    [
        .product(name: "SwiftQEMU", package: "swift-qemu"),
    ]
}
#endif

